//Connects to any running instance of the Unity editor on the local network (broadcast) with the project name of "myunitygame".
             api.Connect("*", ".*?myunitygame.**");

             //Connects to any running instance of the Unity editor on the local machine with the project name of "myunitygame".
             api.Connect("localhost", ".*?myunitygame.*");

             //Connects to any running instance of the Unity editor on the local network.
             api.Connect("*");

//Double-clicks the left mouse button at the position 0, 0 for 30 frames with the left mouse button while holding the left-shift key for 3 frames, and the left-CTRL key for 5 frames.
            api.DoubleClickEx(MouseButtons.LEFT, new Vector2 (0, 0), 30,
                new KeyCode[] { KeyCode.LeftControl }, 5,
                new KeyCode[] { KeyCode.LeftShift }, 3,
                500, 30);

//Double-clicks the left mouse button at the position 0, 0 for 30 frames with the left mouse button while holding the left-shift key for 3 frames, and the left-CTRL key for 5 frames.
            api.DoubleClickEx(MouseButtons.LEFT, 0, 0, 30,
                new KeyCode[] { KeyCode.LeftControl }, 5,
                new KeyCode[] { KeyCode.LeftShift }, 3,
                500, 30);

// Sends a script to the GDIOAgent to print "Hello World" to the Unity console, then adds two numbers and prints the result.
string msScript = @"
    print('Hello World')
    local num = 1 + 1
    print(num)";

api.ExecuteScript(msScript);

// Schedules a script to output some text to the Unity console every 10 frames.
string msScript = "print('Scheduled script executed.')";

string scriptID = api.ScheduleScript(msScript, ScriptExecutionMode.EveryNthFrames, 10);

// The returned GameConnectionDetails object can be used to retrieve information about the connected game.
GameConnectionDetails gameDetails = api.GetConnectedGameDetails();
Console.WriteLine("Connection Address: " + gameDetails.Addr);
Console.WriteLine("Connection Port: " + gameDetails.Port.ToString());
if (gameDetails.IsEditor)
    Console.WriteLine("Testing in editor");
else {
    Console.WriteLine("Testing on platform: " + gameDetails.Platform);
    Console.WriteLine("Path to game: " + gameDetails.GamePath);
}

// Can be used as input for time-sensitive functions such as input.
