 }

// Get all methods on a component
HashSet<gdio.common.objects.MethodInfo> methodList = api.GetMethodList("//*[@name='Player']/fn:component('PlayerController')");

// Iterate through the methods
  foreach (MethodInfo entry in methodList)
  {
    Console.WriteLine("Name"+entry.MethodName + "MethodType "+entry.ReturnTypeFullName);
    List<string> argumentNamesList = entry.ArgumentNames.ToList();
    List<string> argumentTypeList = entry.ArgumentTypeFullNames.ToList();
    for (int i = 0; i < argumentNamesList.Count(); i++)
    {
        Console.WriteLine("\t" + argumentNamesList[i] + ":"+ argumentTypeList[i]);
    }
  }

